{
  "name": "Lumière AI Studio",
  "description": "High-precision AI fashion photoshoot generator. Transforms single reference photos into full professional catalog sets."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GeneratedImage {
  id: string;
  label: string;
  url: string;
  timestamp: number;
}

export interface PoseConfig {
  id: string;
  label: string;
  promptDescription: string;
}

export enum AppState {
  CHECKING_KEY = 'CHECKING_KEY',
  UPLOAD = 'UPLOAD',
  GENERATING = 'GENERATING',
  RESULTS = 'RESULTS',
  ERROR = 'ERROR'
}

export interface GenerationProgress {
  total: number;
  completed: number;
  currentTask: string;
}

import { PoseConfig } from './types';

export const POSES: PoseConfig[] = [
  {
    id: 'front_view',
    label: 'Front View',
    promptDescription: 'Front View: Model facing camera directly, neutral confident pose, arms relaxed. Fashion catalog style. Full visibility of front clothing details.'
  },
  {
    id: 'left_angle',
    label: 'Left Side Angle',
    promptDescription: 'Left Side Angle: Body rotated 45 degrees left, face turned slightly towards camera. Natural standing posture.'
  },
  {
    id: 'right_angle',
    label: 'Right Side Angle',
    promptDescription: 'Right Side Angle: Body rotated 45 degrees right, face turned slightly towards camera. Natural standing posture.'
  },
  {
    id: 'back_view',
    label: 'Back View',
    promptDescription: 'Back View: Full back visibility. Clothing back details clearly visible. Head neutral.'
  },
  {
    id: 'full_body',
    label: 'Full Body View',
    promptDescription: 'Full Body View: Head to toe visible. Balanced stance. Fashion catalog posture.'
  },
  {
    id: 'pose_1',
    label: 'Pose Variation 1',
    promptDescription: 'Pose Variation 1: One hand on waist, slight hip shift. Professional fashion pose.'
  },
  {
    id: 'pose_2',
    label: 'Pose Variation 2',
    promptDescription: 'Pose Variation 2: Arms crossed or soft hand movement near chest. Editorial but realistic fashion pose.'
  }
];

export const SYSTEM_INSTRUCTION = `
You are a high-precision fashion photoshoot generation AI.
Your task is to generate professional photoshoot images from the uploaded reference image.

CRITICAL CONSTRAINTS (MUST FOLLOW STRICTLY):
1. The model’s FACE must remain 100% IDENTICAL to the reference image.
2. Facial structure, skin tone, eye shape, nose, lips, jawline, and expression style must NOT change.
3. Body type, height proportion, posture realism, and limb proportions must remain consistent.
4. Clothing must remain EXACTLY THE SAME: Same fabric, color, fit, texture, neckline, sleeves, length, and design details.
5. Do NOT modify clothing folds, branding, prints, or stitching patterns.
6. No beautification, no face swapping, no AI face reinterpretation.
7. Preserve real human anatomy and natural fashion modeling proportions.
8. Remove blur and noise while keeping identity intact.

BACKGROUND: Pure light grey professional e-commerce background with soft floor shadow.
LIGHTING: Softbox studio lighting, balanced highlights and shadows. No dramatic cinematic lighting.
QUALITY: Ultra-sharp, DSLR-quality, 8K resolution.
`;

import { GoogleGenAI } from "@google/genai";
import { POSES, SYSTEM_INSTRUCTION } from '../constants';
import { PoseConfig, GeneratedImage } from '../types';

// Helper to convert blob to base64 for display/download if needed (though API returns base64)
export const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

export const generatePhotoshoot = async (
  referenceImageBase64: string,
  onProgress: (completed: number, total: number, task: string) => void
): Promise<GeneratedImage[]> => {
  // Use the specific model as requested for high quality
  const MODEL_NAME = 'gemini-3-pro-image-preview';

  // Clean base64 string if it contains metadata header
  const cleanBase64 = referenceImageBase64.split(',')[1] || referenceImageBase64;

  const results: GeneratedImage[] = [];
  let completedCount = 0;

  // Process poses in batches to be efficient but not overwhelm rate limits
  const BATCH_SIZE = 2; 

  // We use the environment key which is injected after user selection
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found. Please select a key first.");
  }

  for (let i = 0; i < POSES.length; i += BATCH_SIZE) {
    const batch = POSES.slice(i, i + BATCH_SIZE);

    const batchPromises = batch.map(async (pose) => {
       // Create a NEW instance for each call as per guidance (especially for stateful keys)
       const ai = new GoogleGenAI({ apiKey });

       onProgress(completedCount, POSES.length, `Generating ${pose.label}...`);

       try {
         const response = await ai.models.generateContent({
           model: MODEL_NAME,
           contents: {
             parts: [
               {
                 text: `${SYSTEM_INSTRUCTION}\n\nGENERATE THIS SPECIFIC SHOT:\n${pose.promptDescription}\n\nEnsure the person is IDENTICAL to the reference image provided.`
               },
               {
                 inlineData: {
                   mimeType: 'image/jpeg', // Assuming jpeg/png input, API handles generic types well
                   data: cleanBase64
                 }
               }
             ]
           },
           config: {
             // Image generation config for the preview model
             imageConfig: {
                aspectRatio: "3:4", // Standard fashion aspect ratio
                imageSize: "2K", // High quality
             },
             // Explicitly request thinking budget for better adherence to constraints if using a thinking model, 
             // but strictly for image generation models, standard config applies.
           }
         });

         // Extract image
         let imageUrl: string | null = null;

         if (response.candidates && response.candidates[0].content.parts) {
           for (const part of response.candidates[0].content.parts) {
             if (part.inlineData && part.inlineData.data) {
               imageUrl = `data:image/png;base64,${part.inlineData.data}`;
               break;
             }
           }
         }

         if (!imageUrl) {
           console.warn(`No image generated for ${pose.label}`);
           return null;
         }

         return {
           id: pose.id,
           label: pose.label,
           url: imageUrl,
           timestamp: Date.now()
         };

       } catch (error) {
         console.error(`Error generating ${pose.label}:`, error);
         return null;
       }
    });

    const batchResults = await Promise.all(batchPromises);

    batchResults.forEach(res => {
      if (res) results.push(res);
    });

    completedCount += batch.length;
    onProgress(Math.min(completedCount, POSES.length), POSES.length, "Processing...");
  }

  return results;
};

