import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-4 py-3 rounded-lg font-medium transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-zinc-950 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-white text-black hover:bg-zinc-200 focus:ring-white",
    secondary: "bg-zinc-800 text-white hover:bg-zinc-700 focus:ring-zinc-700",
    outline: "bg-transparent border border-zinc-700 text-zinc-300 hover:bg-zinc-900 focus:ring-zinc-700"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React, { useRef, useState } from 'react';
import { Upload, Image as ImageIcon, AlertCircle } from 'lucide-react';
import { Button } from './Button';

interface UploadZoneProps {
  onImageSelected: (base64: string) => void;
}

export const UploadZone: React.FC<UploadZoneProps> = ({ onImageSelected }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const processFile = (file: File) => {
    setError(null);
    if (!file.type.startsWith('image/')) {
      setError("Please upload a valid image file (JPG, PNG).");
      return;
    }

    // Check size (limit to 10MB approx)
    if (file.size > 10 * 1024 * 1024) {
      setError("Image size too large. Please use an image under 10MB.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      if (e.target?.result) {
        onImageSelected(e.target.result as string);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = () => {
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files?.[0]) {
      processFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      processFile(e.target.files[0]);
    }
  };

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div 
        className={`
          relative border-2 border-dashed rounded-2xl p-12 text-center transition-all duration-300
          ${isDragging ? 'border-white bg-zinc-900' : 'border-zinc-800 bg-zinc-950/50'}
          ${error ? 'border-red-500/50' : ''}
        `}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
      >
        <div className="flex flex-col items-center gap-6">
          <div className="w-20 h-20 bg-zinc-900 rounded-full flex items-center justify-center border border-zinc-800">
            {isDragging ? (
              <Upload className="w-8 h-8 text-white animate-bounce" />
            ) : (
              <ImageIcon className="w-8 h-8 text-zinc-400" />
            )}
          </div>

          <div className="space-y-2">
            <h3 className="text-xl font-semibold text-white">Upload Reference Photo</h3>
            <p className="text-zinc-400 max-w-sm mx-auto">
              Drag & drop your original low-quality photo here, or click to browse.
            </p>
          </div>

          <input 
            type="file" 
            ref={fileInputRef}
            onChange={handleChange}
            accept="image/png, image/jpeg, image/jpg, image/webp"
            className="hidden"
          />

          <Button onClick={() => fileInputRef.current?.click()}>
            Select Image
          </Button>

          {error && (
            <div className="flex items-center gap-2 text-red-400 bg-red-950/30 px-4 py-2 rounded-lg border border-red-900/50">
              <AlertCircle className="w-4 h-4" />
              <span className="text-sm">{error}</span>
            </div>
          )}

          <div className="mt-4 pt-6 border-t border-zinc-800 w-full">
            <p className="text-xs text-zinc-500 uppercase tracking-wider mb-3">Best Results With</p>
            <div className="grid grid-cols-3 gap-2 text-xs text-zinc-400">
              <div className="bg-zinc-900/50 p-2 rounded border border-zinc-800">Full Body Shot</div>
              <div className="bg-zinc-900/50 p-2 rounded border border-zinc-800">Clear Lighting</div>
              <div className="bg-zinc-900/50 p-2 rounded border border-zinc-800">Simple Background</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { GeneratedImage } from '../types';
import { Download, Maximize2, X } from 'lucide-react';
import { Button } from './Button';

interface GalleryProps {
  images: GeneratedImage[];
  onReset: () => void;
}

export const Gallery: React.FC<GalleryProps> = ({ images, onReset }) => {
  const [selectedImage, setSelectedImage] = useState<GeneratedImage | null>(null);

  const handleDownload = async (url: string, filename: string) => {
    const link = document.createElement('a');
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDownloadAll = () => {
    images.forEach(img => {
      handleDownload(img.url, `${img.label.toLowerCase().replace(/\s+/g, '_')}.png`);
    });
  };

  return (
    <div className="w-full space-y-8 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-white">Photoshoot Results</h2>
          <p className="text-zinc-400">Generated {images.length} high-fidelity studio shots.</p>
        </div>
        <div className="flex gap-3">
          <Button variant="outline" onClick={onReset}>
            New Shoot
          </Button>
          <Button onClick={handleDownloadAll}>
            <Download className="w-4 h-4 mr-2" />
            Download All
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
        {images.map((img) => (
          <div 
            key={img.id} 
            className="group relative aspect-[3/4] bg-zinc-900 rounded-xl overflow-hidden border border-zinc-800 hover:border-zinc-600 transition-colors"
          >
            <img 
              src={img.url} 
              alt={img.label} 
              className="w-full h-full object-cover"
            />

            <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex flex-col justify-end p-4">
              <p className="text-white font-medium text-sm mb-2">{img.label}</p>
              <div className="flex gap-2">
                <button 
                  onClick={() => setSelectedImage(img)}
                  className="p-2 bg-white/10 backdrop-blur-md rounded-lg hover:bg-white/20 text-white transition-colors"
                >
                  <Maximize2 className="w-4 h-4" />
                </button>
                <button 
                  onClick={() => handleDownload(img.url, `${img.label}.png`)}
                  className="p-2 bg-white text-black rounded-lg hover:bg-zinc-200 transition-colors"
                >
                  <Download className="w-4 h-4" />
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Lightbox Modal */}
      {selectedImage && (
        <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-4 md:p-10">
          <button 
            onClick={() => setSelectedImage(null)}
            className="absolute top-6 right-6 p-2 text-zinc-400 hover:text-white"
          >
            <X className="w-8 h-8" />
          </button>

          <div className="relative max-w-full max-h-full flex flex-col items-center">
             <img 
               src={selectedImage.url} 
               alt={selectedImage.label} 
               className="max-h-[85vh] w-auto rounded-lg shadow-2xl"
             />
             <div className="mt-6 flex items-center gap-4">
                <span className="text-white font-medium text-lg">{selectedImage.label}</span>
                <Button onClick={() => handleDownload(selectedImage.url, `${selectedImage.label}.png`)}>
                  <Download className="w-4 h-4 mr-2" />
                  Download High-Res
                </Button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { UploadZone } from './components/UploadZone';
import { Gallery } from './components/Gallery';
import { Button } from './components/Button';
import { AppState, GeneratedImage, GenerationProgress } from './types';
import { generatePhotoshoot } from './services/geminiService';
import { Loader2, KeyRound } from 'lucide-react';

// Extend window for the custom AI Studio method
declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.CHECKING_KEY);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [progress, setProgress] = useState<GenerationProgress>({ total: 0, completed: 0, currentTask: '' });
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Initial Key Check
  useEffect(() => {
    checkKey();
  }, []);

  const checkKey = async () => {
    if (window.aistudio && await window.aistudio.hasSelectedApiKey()) {
      setState(AppState.UPLOAD);
    } else {
      // If prompt logic fails or environment is different, we can default to upload if we trust the env vars,
      // but strictly following guidance for Gemini 3 Pro Preview:
      setState(AppState.CHECKING_KEY);
    }
  };

  const handleSelectKey = async () => {
    setErrorMsg(null);
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        // Assume success as per guidance to avoid race condition
        setState(AppState.UPLOAD);
      } catch (e) {
        console.error(e);
        setErrorMsg("Failed to select API key. Please try again.");
      }
    } else {
       // Fallback for dev environments where window.aistudio might not be mocked
       console.warn("window.aistudio not found, proceeding with process.env.API_KEY if available");
       setState(AppState.UPLOAD);
    }
  };

  const handleImageSelected = async (base64: string) => {
    setUploadedImage(base64);
    setState(AppState.GENERATING);
    setErrorMsg(null);
    setGeneratedImages([]);

    try {
      const results = await generatePhotoshoot(base64, (completed, total, task) => {
        setProgress({ completed, total, currentTask: task });
      });

      if (results.length === 0) {
        throw new Error("No images were successfully generated. Please try a different reference photo.");
      }

      setGeneratedImages(results);
      setState(AppState.RESULTS);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unexpected error occurred during generation.");
      setState(AppState.UPLOAD); // Go back to upload but keep the error visible if we want, or make a separate error state
    }
  };

  const handleReset = () => {
    setUploadedImage(null);
    setGeneratedImages([]);
    setState(AppState.UPLOAD);
    setErrorMsg(null);
  };

  return (
    <div className="min-h-screen bg-black text-zinc-100 font-sans selection:bg-white selection:text-black">
      <Header />

      <main className="max-w-7xl mx-auto px-4 py-12 md:py-20">

        {/* Error Banner */}
        {errorMsg && (
          <div className="mb-8 mx-auto max-w-2xl bg-red-950/30 border border-red-900/50 text-red-200 px-6 py-4 rounded-xl flex items-center gap-3">
             <div className="w-2 h-2 rounded-full bg-red-500" />
             {errorMsg}
          </div>
        )}

        {/* STATE: KEY SELECTION */}
        {state === AppState.CHECKING_KEY && (
          <div className="max-w-md mx-auto text-center space-y-8 mt-10">
            <div className="w-24 h-24 bg-zinc-900 rounded-3xl mx-auto flex items-center justify-center border border-zinc-800">
              <KeyRound className="w-10 h-10 text-zinc-400" />
            </div>
            <div className="space-y-2">
              <h2 className="text-3xl font-bold tracking-tight text-white">Access Required</h2>
              <p className="text-zinc-400">
                To use the Lumière AI Studio high-precision models, please select a billing-enabled Google Cloud API key.
              </p>
            </div>
            <div className="space-y-4">
              <Button onClick={handleSelectKey} fullWidth>
                Select API Key
              </Button>
              <p className="text-xs text-zinc-600">
                <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="underline hover:text-zinc-400">
                  View billing documentation
                </a>
              </p>
            </div>
          </div>
        )}

        {/* STATE: UPLOAD */}
        {state === AppState.UPLOAD && (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="text-center space-y-4">
              <h1 className="text-4xl md:text-5xl font-bold tracking-tight text-white">
                Turn One Shot Into A <span className="text-transparent bg-clip-text bg-gradient-to-r from-white to-zinc-500">Full Catalog</span>
              </h1>
              <p className="text-lg text-zinc-400 max-w-2xl mx-auto">
                Upload a raw photo. Get 7 distinct, professional fashion studio angles.
                Identity preserved. 8K Quality.
              </p>
            </div>

            <UploadZone onImageSelected={handleImageSelected} />
          </div>
        )}

        {/* STATE: GENERATING */}
        {state === AppState.GENERATING && (
          <div className="max-w-2xl mx-auto text-center mt-12 space-y-8 animate-in zoom-in-95 duration-500">
            <div className="relative w-full aspect-video bg-zinc-900 rounded-2xl overflow-hidden border border-zinc-800">
              {/* Reference Image Blurred in BG */}
              {uploadedImage && (
                <img 
                  src={uploadedImage} 
                  alt="Reference" 
                  className="absolute inset-0 w-full h-full object-cover opacity-20 blur-xl scale-110"
                />
              )}

              <div className="absolute inset-0 flex flex-col items-center justify-center p-8">
                <Loader2 className="w-12 h-12 text-white animate-spin mb-6" />
                <h3 className="text-2xl font-bold text-white mb-2">Generating Photoshoot</h3>
                <p className="text-zinc-400 mb-8">{progress.currentTask}</p>

                <div className="w-full h-2 bg-zinc-800 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-white transition-all duration-500 ease-out"
                    style={{ width: `${(progress.completed / progress.total) * 100}%` }}
                  />
                </div>
                <div className="mt-4 flex justify-between w-full text-xs text-zinc-500 uppercase tracking-widest font-medium">
                   <span>Processing</span>
                   <span>{progress.completed} / {progress.total} Shots</span>
                </div>
              </div>
            </div>
            <p className="text-sm text-zinc-500 animate-pulse">
              This process utilizes the Gemini 3 Pro Vision model and may take up to 60 seconds.
            </p>
          </div>
        )}

        {/* STATE: RESULTS */}
        {state === AppState.RESULTS && (
          <Gallery images={generatedImages} onReset={handleReset} />
        )}

      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { UploadZone } from './components/UploadZone';
import { Gallery } from './components/Gallery';
import { Button } from './components/Button';
import { AppState, GeneratedImage, GenerationProgress } from './types';
import { generatePhotoshoot } from './services/geminiService';
import { Loader2, KeyRound } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.CHECKING_KEY);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [progress, setProgress] = useState<GenerationProgress>({ total: 0, completed: 0, currentTask: '' });
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Initial Key Check
  useEffect(() => {
    checkKey();
  }, []);

  const checkKey = async () => {
    // Cast window to any to access aistudio to avoid type conflicts with global definition
    const win = window as any;
