  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [progress, setProgress] = useState<GenerationProgress>({ total: 0, completed: 0, currentTask: '' });
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Load history from localStorage on initial mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed)) {
          setHistory(parsed);
        }
      } catch (err) {
        console.error("Failed to restore history:", err);
        localStorage.removeItem(STORAGE_KEY);
      }
    }
  }, []);

  // Helper to persist history with recursive trimming to handle QuotaExceededError
  const persistHistory = useCallback((items: HistoryItem[]) => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
    } catch (e) {
      if (e instanceof DOMException && (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED')) {
        console.warn("LocalStorage quota exceeded. Trimming history archive...");
        if (items.length > 1) {
          // Remove the oldest item (last in chronological array) and try again
          const trimmed = items.slice(0, -1);
          setHistory(trimmed); // This update will trigger the effect again
        } else {
          // If even a single session is too large for storage
          console.error("Single session exceeds storage limits.");
          setErrorMsg("This photoshoot is too large to save in browser history. Try a smaller file next time.");
        }
      }
    }
  }, []);

  // Sync state to storage whenever history changes
  useEffect(() => {
    if (history.length > 0) {
      persistHistory(history);
    } else {
      localStorage.removeItem(STORAGE_KEY);
    }
  }, [history, persistHistory]);

  const handleImageSelected = async (base64: string) => {
    setUploadedImage(base64);
    setState(AppState.GENERATING);
    setErrorMsg(null);
    setGeneratedImages([]);

    try {
      const results = await generatePhotoshoot(base64, (completed, total, task) => {
        setProgress({ completed, total, currentTask: task });
      });

      if (results.length === 0) {
        throw new Error("No images were successfully generated.");
      }

      setGeneratedImages(results);
      setState(AppState.RESULTS);

      // Create new history entry
      const newItem: HistoryItem = {
        id: crypto.randomUUID?.() || Math.random().toString(36).substring(7),
        timestamp: Date.now(),
        referenceImage: base64,
        results: results
      };

      setHistory(prev => [newItem, ...prev]);

    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unexpected error occurred during the photoshoot.");
      setState(AppState.UPLOAD);
    }
  };

  const handleReset = () => {
    setUploadedImage(null);
    setGeneratedImages([]);
    setState(AppState.UPLOAD);
    setErrorMsg(null);
  };

