export const SYSTEM_INSTRUCTION = `
You are a high-precision fashion photoshoot generation AI.
Your task is to generate professional photoshoot images from the provided reference images.
You are provided with one or more reference images of the same person and outfit. Use all provided references to achieve maximum precision in identity and clothing detail.

CRITICAL CONSTRAINTS (MUST FOLLOW STRICTLY):
1. The model’s FACE must remain 100% IDENTICAL to the reference images.
2. Facial structure, skin tone, eye shape, nose, lips, jawline, and expression style must NOT change.
3. Body type, height proportion, posture realism, and limb proportions must remain consistent.
4. Clothing must remain EXACTLY THE SAME: Same fabric, color, fit, texture, neckline, sleeves, length, and design details.
5. Do NOT modify clothing folds, branding, prints, or stitching patterns.
6. No beautification, no face swapping, no AI face reinterpretation.
7. Preserve real human anatomy and natural fashion modeling proportions.
8. Remove blur and noise while keeping identity intact.

BACKGROUND: Pure light grey professional e-commerce background with soft floor shadow.
LIGHTING: Softbox studio lighting, balanced highlights and shadows. No dramatic cinematic lighting.
QUALITY: Ultra-sharp, DSLR-quality, 8K resolution.
`;

import { GoogleGenAI } from "@google/genai";
import { POSES, SYSTEM_INSTRUCTION } from '../constants';
import { PoseConfig, GeneratedImage } from '../types';

export const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

export const generatePhotoshoot = async (
  referenceImagesBase64: string[],
  onProgress: (completed: number, total: number, task: string) => void
): Promise<GeneratedImage[]> => {
  const ACTIVE_MODEL = 'gemini-2.5-flash-image';

  const results: GeneratedImage[] = [];
  let completedCount = 0;

  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment.");
  }

  const ai = new GoogleGenAI({ apiKey });

  // Prepare reference parts
  const referenceParts = referenceImagesBase64.map(base64 => {
    const cleanBase64 = base64.split(',')[1] || base64;
    return {
      inlineData: {
        mimeType: 'image/jpeg',
        data: cleanBase64
      }
    };
  });

  for (const pose of POSES) {
     onProgress(completedCount, POSES.length, `Generating ${pose.label}...`);

     try {
       const response = await ai.models.generateContent({
         model: ACTIVE_MODEL,
         contents: {
           parts: [
             {
               text: `${SYSTEM_INSTRUCTION}\n\nGENERATE THIS SPECIFIC SHOT:\n${pose.promptDescription}\n\nUse the provided reference images to ensure the person and clothing are IDENTICAL.`
             },
             ...referenceParts
           ]
         },
         config: {
           imageConfig: {
              aspectRatio: "3:4",
           }
         }
       });

       if (response.candidates && response.candidates[0].content.parts) {
         for (const part of response.candidates[0].content.parts) {
           if (part.inlineData && part.inlineData.data) {
             results.push({
               id: pose.id,
               label: pose.label,
               url: `data:image/png;base64,${part.inlineData.data}`,
               timestamp: Date.now()
             });
             break;
           }
         }
       }
     } catch (e: any) {
       console.error(`Error generating ${pose.label}:`, e);
     }

     completedCount++;
     onProgress(completedCount, POSES.length, "Processing...");
  }

  return results;
};

import React, { useRef, useState } from 'react';
import { Upload, Image as ImageIcon, AlertCircle, X, Plus } from 'lucide-react';
import { Button } from './Button';

interface UploadZoneProps {
  onImagesReady: (base64Array: string[]) => void;
}

export const UploadZone: React.FC<UploadZoneProps> = ({ onImagesReady }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [previews, setPreviews] = useState<string[]>([]);

  const processFiles = (files: FileList | File[]) => {
    setError(null);
    const newFiles = Array.from(files);

    const validFiles = newFiles.filter(file => {
      if (!file.type.startsWith('image/')) {
        setError("Only image files are allowed.");
        return false;
      }
      if (file.size > 10 * 1024 * 1024) {
        setError("Some images are too large (max 10MB per image).");
        return false;
      }
      return true;
    });

    const promises = validFiles.map(file => {
      return new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onload = (e) => resolve(e.target?.result as string);
        reader.readAsDataURL(file);
      });
    });

    Promise.all(promises).then(base64s => {
      setPreviews(prev => [...prev, ...base64s].slice(0, 3)); // Max 3 references for Gemini stability
    });
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = () => {
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) {
      processFiles(e.dataTransfer.files);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      processFiles(e.target.files);
    }
  };

  const removeImage = (index: number) => {
    setPreviews(prev => prev.filter((_, i) => i !== index));
  };

  const handleStartGeneration = () => {
    if (previews.length > 0) {
      onImagesReady(previews);
    }
  };

  return (
    <div className="w-full max-w-3xl mx-auto space-y-6">
      <div 
        className={`
          relative border-2 border-dashed rounded-2xl p-10 text-center transition-all duration-300
          ${isDragging ? 'border-white bg-zinc-900' : 'border-zinc-800 bg-zinc-950/50'}
          ${error ? 'border-red-500/50' : ''}
          ${previews.length > 0 ? 'p-6' : 'p-12'}
        `}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
      >
        {previews.length === 0 ? (
          <div className="flex flex-col items-center gap-6">
            <div className="w-20 h-20 bg-zinc-900 rounded-full flex items-center justify-center border border-zinc-800">
              {isDragging ? (
                <Upload className="w-8 h-8 text-white animate-bounce" />
              ) : (
                <ImageIcon className="w-8 h-8 text-zinc-400" />
              )}
            </div>

            <div className="space-y-2">
              <h3 className="text-xl font-semibold text-white">Upload Reference Photos</h3>
              <p className="text-zinc-400 max-w-sm mx-auto">
                Upload up to 3 photos of the same outfit (e.g., front, back, detail) for maximum AI precision.
              </p>
            </div>

            <input 
              type="file" 
              ref={fileInputRef}
              onChange={handleChange}
              multiple
              accept="image/png, image/jpeg, image/jpg, image/webp"
              className="hidden"
            />

            <Button onClick={() => fileInputRef.current?.click()}>
              Select Images
            </Button>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex flex-wrap justify-center gap-4">
              {previews.map((src, idx) => (
                <div key={idx} className="relative w-32 h-44 bg-zinc-900 rounded-lg overflow-hidden border border-zinc-700">
                  <img src={src} alt="Preview" className="w-full h-full object-cover" />
                  <button 
                    onClick={() => removeImage(idx)}
                    className="absolute top-1 right-1 p-1 bg-black/50 hover:bg-black rounded-full text-white transition-colors"
                  >
                    <X className="w-3 h-3" />
                  </button>
                </div>
              ))}
              {previews.length < 3 && (
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-32 h-44 border-2 border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center gap-2 hover:border-zinc-600 hover:bg-zinc-900/50 transition-all text-zinc-500 hover:text-zinc-300"
                >
                  <Plus className="w-6 h-6" />
                  <span className="text-xs font-medium">Add Angle</span>
                </button>
              )}
            </div>

            <div className="flex flex-col items-center gap-4">
              <Button onClick={handleStartGeneration} className="w-full max-w-xs shadow-[0_0_20px_rgba(255,255,255,0.1)]">
                Start Professional Photoshoot
              </Button>
              <button 
                onClick={() => setPreviews([])}
                className="text-xs text-zinc-500 hover:text-zinc-300 transition-colors uppercase tracking-widest font-bold"
              >
                Clear All
              </button>
            </div>
          </div>
        )}

        <input 
          type="file" 
          ref={fileInputRef}
          onChange={handleChange}
          multiple
          accept="image/png, image/jpeg, image/jpg, image/webp"
          className="hidden"
        />

        {error && (
          <div className="mt-4 flex items-center gap-2 text-red-400 bg-red-950/30 px-4 py-2 rounded-lg border border-red-900/50 justify-center">
            <AlertCircle className="w-4 h-4" />
            <span className="text-sm">{error}</span>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-zinc-950 border border-zinc-900 p-4 rounded-xl">
          <div className="text-zinc-500 text-[10px] uppercase tracking-wider mb-2 font-bold">Recommended</div>
          <div className="text-sm font-medium text-white mb-1">Multi-Angle Capture</div>
          <p className="text-xs text-zinc-500">Provide a front and a back view to help the AI understand the complete outfit structure.</p>
        </div>
        <div className="bg-zinc-950 border border-zinc-900 p-4 rounded-xl">
          <div className="text-zinc-500 text-[10px] uppercase tracking-wider mb-2 font-bold">Detailing</div>
          <div className="text-sm font-medium text-white mb-1">Texture Clarity</div>
          <p className="text-xs text-zinc-500">Close-ups of fabrics or logos ensure branding remains 100% accurate in results.</p>
        </div>
        <div className="bg-zinc-950 border border-zinc-900 p-4 rounded-xl">
          <div className="text-zinc-500 text-[10px] uppercase tracking-wider mb-2 font-bold">Identity</div>
          <div className="text-sm font-medium text-white mb-1">Face Symmetry</div>
          <p className="text-xs text-zinc-500">A clear face shot is prioritized for mapping facial geometry to professional poses.</p>
        </div>
      </div>
    </div>
  );
};

