import { GoogleGenAI } from "@google/genai";
import { PRODUCT_PRESETS, SYSTEM_INSTRUCTION, POSE_STYLES } from '../constants';
import { PoseConfig, GeneratedImage, ProductType, PoseStyle } from '../types';

export const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

// Retry helper for robust API calls
const retryOperation = async <T>(
  operation: () => Promise<T>,
  retries: number = 3,
  delay: number = 2000
): Promise<T> => {
  try {
    return await operation();
  } catch (error: any) {
    // Retry on 500 (Internal), 503 (Service Unavailable), or generic internal errors
    const shouldRetry = 
      retries > 0 && (
        error.status === 500 || 
        error.status === 503 || 
        error.message?.includes('Internal error') ||
        error.message?.includes('Overloaded') ||
        error.message?.includes('500')
      );

    if (shouldRetry) {
      console.warn(`API Error (${error.status || error.message}). Retrying in ${delay}ms... (${retries} attempts left)`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return retryOperation(operation, retries - 1, delay * 2);
    }
    throw error;
  }
};

export const generatePhotoshoot = async (
  referenceImagesBase64: string[],
  productType: ProductType,
  poseStyle: PoseStyle,
  onProgress: (completed: number, total: number, task: string) => void
): Promise<GeneratedImage[]> => {
  // Switched to Pro model for high fidelity
  const ACTIVE_MODEL = 'gemini-3-pro-image-preview';
  const poses = PRODUCT_PRESETS[productType];
  const stylePrompt = POSE_STYLES[poseStyle];

  if (!poses) {
    throw new Error(`Invalid product type: ${productType}`);
  }

  const results: GeneratedImage[] = [];
  let completedCount = 0;

  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment.");
  }

  const ai = new GoogleGenAI({ apiKey });

  // Prepare reference parts
  const referenceParts = referenceImagesBase64.map(base64 => {
    // Extract mime type if available, default to jpeg
    const mimeMatch = base64.match(/^data:(image\/[a-zA-Z]+);base64,/);
    const mimeType = mimeMatch ? mimeMatch[1] : 'image/jpeg';
    const cleanBase64 = base64.split(',')[1] || base64;

    return {
      inlineData: {
        mimeType: mimeType,
        data: cleanBase64
      }
    };
  });

  for (const pose of poses) {
     onProgress(completedCount, poses.length, `Generating ${pose.label}...`);

     try {
       const response = await retryOperation(async () => {
         return await ai.models.generateContent({
           model: ACTIVE_MODEL,
           contents: {
             parts: [
               {
                 text: `${SYSTEM_INSTRUCTION}\n\n${stylePrompt}\n\nGENERATE THIS SPECIFIC SHOT:\n${pose.promptDescription}\n\nUse the provided reference images to ensure the person and clothing are IDENTICAL.`
               },
               ...referenceParts
             ]
           },
           config: {
             imageConfig: {
                aspectRatio: "3:4",
                imageSize: "2K" // Pro model supports high resolution
             }
           }
         });
       });

       if (response.candidates && response.candidates[0].content.parts) {
         for (const part of response.candidates[0].content.parts) {
           if (part.inlineData && part.inlineData.data) {
             results.push({
               id: pose.id,
               label: pose.label,
               url: `data:image/png;base64,${part.inlineData.data}`,
               timestamp: Date.now()
             });
             break;
           }
         }
       }
     } catch (e: any) {
       console.error(`Error generating ${pose.label}:`, e);
       // We log the error but continue to the next pose so the whole batch doesn't fail
     }

     completedCount++;
     onProgress(completedCount, poses.length, "Processing...");
  }

  return results;
};

