import React, { useRef, useState, useEffect } from 'react';
import { Upload, Image as ImageIcon, AlertCircle, X, Plus, Shirt, Check, Moon, LayoutTemplate, Box, Sun, Zap, Palette } from 'lucide-react';
import { Button } from './Button';
import { ProductType, PoseStyle } from '../types';

interface UploadZoneProps {
  onImagesReady: (base64Array: string[], productType: ProductType, poseStyle: PoseStyle) => void;
}

const PRODUCT_OPTIONS: { id: ProductType; label: string; desc: string }[] = [
  { id: 'TOPS', label: 'Tops / Tees', desc: 'Focus on neckline, sleeves, and upper body fit.' },
  { id: 'DRESSES', label: 'Dresses', desc: 'Full body flow, silhouette, and length.' },
  { id: 'COORDS', label: 'Co-ord Sets', desc: 'Matching sets with top and bottom focus.' },
  { id: 'KURTI', label: 'Kurti / Tunic', desc: 'Ethnic wear details, side cuts, and yokes.' },
];

const STYLE_OPTIONS: { id: PoseStyle; label: string; desc: string; icon: React.ElementType }[] = [
  { id: 'STUDIO_WHITE', label: 'Studio White', desc: 'Pure white background. Clean, high-key commercial.', icon: LayoutTemplate },
  { id: 'STUDIO_GREY', label: 'Studio Grey', desc: 'Soft grey background. Professional catalog look.', icon: Box },
  { id: 'OUTDOOR_DAYLIGHT', label: 'Outdoor Daylight', desc: 'Natural sunlight, blurred park/street background.', icon: Sun },
  { id: 'STREET_WEAR', label: 'Gen-Z / Street', desc: 'Urban vibes, concrete texture, edgy posing.', icon: Zap },
  { id: 'STUDIO_COLORS', label: 'Studio Colors', desc: 'Soft pastel backgrounds (Pink, Beige, Blue).', icon: Palette },
  { id: 'URBAN_NIGHT', label: 'Urban Night', desc: 'Flash-lit rooftop editorial. (Dresses/Tops/Coords)', icon: Moon },
];

const MAX_IMAGES = 10;

export const UploadZone: React.FC<UploadZoneProps> = ({ onImagesReady }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [selectedType, setSelectedType] = useState<ProductType>('TOPS');
  const [selectedStyle, setSelectedStyle] = useState<PoseStyle>('STUDIO_WHITE');
  const [isDragging, setIsDragging] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [previews, setPreviews] = useState<string[]>([]);

  // Effect to reset incompatible styles when product type changes
  useEffect(() => {
    if (selectedStyle === 'URBAN_NIGHT' && selectedType === 'KURTI') {
      setSelectedStyle('STUDIO_WHITE');
    }
  }, [selectedType, selectedStyle]);

  const processFiles = (files: FileList | File[]) => {
    setError(null);
    const newFiles = Array.from(files);

    const validFiles = newFiles.filter(file => {
      if (!file.type.startsWith('image/')) {
        setError("Only image files are allowed.");
        return false;
      }
      // Individual file limit 10MB
      if (file.size > 10 * 1024 * 1024) {
        setError("Some images are too large (max 10MB per image).");
        return false;
      }
      return true;
    });

    const promises = validFiles.map(file => {
      return new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onload = (e) => resolve(e.target?.result as string);
        reader.readAsDataURL(file);
      });
    });

    Promise.all(promises).then(base64s => {
      setPreviews(prev => [...prev, ...base64s].slice(0, MAX_IMAGES));
    });
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = () => {
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) {
      processFiles(e.dataTransfer.files);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      processFiles(e.target.files);
    }
  };

  const removeImage = (index: number) => {
    setPreviews(prev => prev.filter((_, i) => i !== index));
  };

  const handleStartGeneration = () => {
    if (previews.length > 0) {
      onImagesReady(previews, selectedType, selectedStyle);
    }
  };

  const isStyleDisabled = (styleId: PoseStyle) => {
    if (styleId === 'URBAN_NIGHT') {
      return selectedType === 'KURTI';
    }
    return false;
  };

  return (
    <div className="w-full max-w-4xl mx-auto space-y-8">

      {/* Step 1: Category Selection */}
      <div className="space-y-4">
        <h3 className="text-sm font-bold text-zinc-500 uppercase tracking-widest text-center">1. Select Product Category</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
          {PRODUCT_OPTIONS.map((opt) => (
            <button
              key={opt.id}
              onClick={() => setSelectedType(opt.id)}
              className={`
                relative p-4 rounded-xl border text-left transition-all duration-200 group
                ${selectedType === opt.id 
                  ? 'bg-white border-white text-black shadow-[0_0_20px_rgba(255,255,255,0.2)]' 
                  : 'bg-zinc-900/50 border-zinc-800 text-zinc-400 hover:border-zinc-600 hover:bg-zinc-900'}
              `}
            >
              {selectedType === opt.id && (
                <div className="absolute top-2 right-2">
                  <Check className="w-4 h-4 text-black" />
                </div>
              )}
              <div className="mb-2">
                <Shirt className={`w-6 h-6 ${selectedType === opt.id ? 'text-black' : 'text-zinc-500 group-hover:text-zinc-300'}`} />
              </div>
              <div className="font-bold text-sm mb-1">{opt.label}</div>
              <div className={`text-[10px] leading-tight ${selectedType === opt.id ? 'text-zinc-600' : 'text-zinc-500'}`}>
                {opt.desc}
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Step 2: Mood Selection */}
      <div className="space-y-4">
        <h3 className="text-sm font-bold text-zinc-500 uppercase tracking-widest text-center">2. Select Photoshoot Style</h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
          {STYLE_OPTIONS.map((opt) => {
            const disabled = isStyleDisabled(opt.id);
            const Icon = opt.icon;
            return (
              <button
                key={opt.id}
                onClick={() => !disabled && setSelectedStyle(opt.id)}
                disabled={disabled}
                className={`
                  relative p-4 rounded-xl border text-left transition-all duration-200 group flex items-start gap-3
                  ${disabled 
                    ? 'opacity-40 cursor-not-allowed bg-zinc-950 border-zinc-900 text-zinc-600'
                    : selectedStyle === opt.id 
                      ? 'bg-zinc-100 border-zinc-100 text-black shadow-[0_0_15px_rgba(255,255,255,0.1)]' 
                      : 'bg-zinc-900/30 border-zinc-800 text-zinc-400 hover:border-zinc-600 hover:bg-zinc-900'}
                `}
              >
                {selectedStyle === opt.id && !disabled && (
                  <div className="absolute top-2 right-2">
                    <Check className="w-4 h-4 text-black" />
                  </div>
                )}
                <div className="mt-1">
                  <Icon className={`w-5 h-5 ${selectedStyle === opt.id && !disabled ? 'text-black' : 'text-zinc-600 group-hover:text-zinc-400'}`} />
                </div>
                <div>
                  <div className="font-bold text-sm mb-0.5">{opt.label}</div>
                  <div className={`text-[10px] leading-tight ${selectedStyle === opt.id && !disabled ? 'text-zinc-600' : 'text-zinc-500'}`}>
                    {opt.desc}
                  </div>
                </div>
              </button>
            );
          })}
        </div>
      </div>

      {/* Step 3: Upload */}
      <div className="space-y-4">
        <h3 className="text-sm font-bold text-zinc-500 uppercase tracking-widest text-center">3. Upload References</h3>
        <div 
          className={`
            relative border-2 border-dashed rounded-2xl p-10 text-center transition-all duration-300
            ${isDragging ? 'border-white bg-zinc-900' : 'border-zinc-800 bg-zinc-950/50'}
            ${error ? 'border-red-500/50' : ''}
            ${previews.length > 0 ? 'p-6' : 'p-12'}
          `}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          {previews.length === 0 ? (
            <div className="flex flex-col items-center gap-6">
              <div className="w-20 h-20 bg-zinc-900 rounded-full flex items-center justify-center border border-zinc-800">
                {isDragging ? (
                  <Upload className="w-8 h-8 text-white animate-bounce" />
                ) : (
                  <ImageIcon className="w-8 h-8 text-zinc-400" />
                )}
              </div>

              <div className="space-y-2">
                <h3 className="text-xl font-semibold text-white">Upload Photos</h3>
                <p className="text-zinc-400 max-w-sm mx-auto text-sm">
                  Upload up to {MAX_IMAGES} photos (Front, Back, Detail) for best results.
                </p>
              </div>

              <input 
                type="file" 
                ref={fileInputRef}
                onChange={handleChange}
                multiple
                accept="image/png, image/jpeg, image/jpg, image/webp"
                className="hidden"
              />

              <Button onClick={() => fileInputRef.current?.click()}>
                Select Images
              </Button>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="flex flex-wrap justify-center gap-4">
                {previews.map((src, idx) => (
                  <div key={idx} className="relative w-32 h-44 bg-zinc-900 rounded-lg overflow-hidden border border-zinc-700 shadow-lg">
                    <img src={src} alt="Preview" className="w-full h-full object-cover" />
                    <button 
                      onClick={() => removeImage(idx)}
                      className="absolute top-1 right-1 p-1 bg-black/50 hover:bg-black rounded-full text-white transition-colors"
                    >
                      <X className="w-3 h-3" />
                    </button>
                    <div className="absolute bottom-0 inset-x-0 bg-black/60 py-1 text-[9px] text-white uppercase font-bold">
                      Ref {idx + 1}
                    </div>
                  </div>
                ))}
                {previews.length < MAX_IMAGES && (
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-32 h-44 border-2 border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center gap-2 hover:border-zinc-600 hover:bg-zinc-900/50 transition-all text-zinc-500 hover:text-zinc-300"
                  >
                    <Plus className="w-6 h-6" />
                    <span className="text-xs font-medium">Add Angle</span>
                  </button>
                )}
              </div>

              <div className="flex flex-col items-center gap-4 pt-4">
                <Button onClick={handleStartGeneration} className="w-full max-w-md shadow-[0_0_20px_rgba(255,255,255,0.1)] h-12 text-lg">
                  Generate {selectedType.charAt(0) + selectedType.slice(1).toLowerCase()} Catalog
                </Button>
                <button 
                  onClick={() => setPreviews([])}
                  className="text-xs text-zinc-500 hover:text-zinc-300 transition-colors uppercase tracking-widest font-bold"
                >
                  Clear All
                </button>
              </div>
            </div>
          )}

          <input 
            type="file" 
            ref={fileInputRef}
            onChange={handleChange}
            multiple
            accept="image/png, image/jpeg, image/jpg, image/webp"
            className="hidden"
          />

          {error && (
            <div className="mt-4 flex items-center gap-2 text-red-400 bg-red-950/30 px-4 py-2 rounded-lg border border-red-900/50 justify-center">
              <AlertCircle className="w-4 h-4" />
              <span className="text-sm">{error}</span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Header } from './components/Header';
import { UploadZone } from './components/UploadZone';
import { Gallery } from './components/Gallery';
import { HistoryView } from './components/HistoryView';
import { Button } from './components/Button';
import { AppState, GeneratedImage, GenerationProgress, HistoryItem, ProductType, PoseStyle } from './types';
import { generatePhotoshoot } from './services/geminiService';
import { Loader2, KeyRound } from 'lucide-react';

// IndexedDB configuration for robust storage of high-res base64 images
const DB_NAME = 'LumiereStudioDB';
const STORE_NAME = 'history';
const DB_VERSION = 2; // Incremented version to handle referenceImages array

const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onupgradeneeded = (event) => {
      const db = request.result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
      // Migration logic if needed could go here
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.CHECKING_KEY);
  const [referenceImages, setReferenceImages] = useState<string[]>([]);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [progress, setProgress] = useState<GenerationProgress>({ total: 0, completed: 0, currentTask: '' });
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Initial Check for API Key & Load History
  useEffect(() => {
    const init = async () => {
      // 1. Check API Key Status
      const win = window as any;
      if (win.aistudio && await win.aistudio.hasSelectedApiKey()) {
        setState(AppState.UPLOAD);
      } else {
        setState(AppState.CHECKING_KEY);
      }

      // 2. Load History
      try {
        const db = await openDB();
        const transaction = db.transaction(STORE_NAME, 'readonly');
        const store = transaction.objectStore(STORE_NAME);
        const request = store.getAll();
        request.onsuccess = () => {
          const raw = request.result as any[];
          // Backward compatibility for single referenceImage history
          const migrated = raw.map(item => ({
            ...item,
            referenceImages: item.referenceImages || (item.referenceImage ? [item.referenceImage] : []),
            productType: item.productType || 'TOPS', // Default for old items
            poseStyle: item.poseStyle || 'STUDIO_WHITE'
          })) as HistoryItem[];

          const sorted = migrated.sort((a, b) => b.timestamp - a.timestamp);
          setHistory(sorted);
        };
      } catch (err) {
        console.error("Failed to load history from IndexedDB", err);
      }
    };
    init();
  }, []);

  const handleSelectKey = async () => {
    setErrorMsg(null);
    const win = window as any;
    if (win.aistudio) {
      try {
        await win.aistudio.openSelectKey();
        setState(AppState.UPLOAD);
      } catch (e) {
        setErrorMsg("Failed to select API key. Please try again.");
      }
    } else {
      // Fallback for dev environments
      setState(AppState.UPLOAD);
    }
  };

  const handleImagesSelected = async (base64Array: string[], productType: ProductType, poseStyle: PoseStyle) => {
    setReferenceImages(base64Array);
    setState(AppState.GENERATING);
    setErrorMsg(null);
    setGeneratedImages([]);

    try {
      const results = await generatePhotoshoot(base64Array, productType, poseStyle, (completed, total, task) => {
        setProgress({ completed, total, currentTask: task });
      });

      if (results.length === 0) {
        throw new Error("No images were successfully generated.");
      }

      const newItem: HistoryItem = {
        id: crypto.randomUUID?.() || Math.random().toString(36).substring(7),
        timestamp: Date.now(),
        referenceImages: base64Array,
        productType: productType,
        poseStyle: poseStyle,
        results: results
      };

      // Save to IndexedDB
      const db = await openDB();
      const transaction = db.transaction(STORE_NAME, 'readwrite');
      transaction.objectStore(STORE_NAME).add(newItem);

      setGeneratedImages(results);
      setHistory(prev => [newItem, ...prev]);
      setState(AppState.RESULTS);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unexpected error occurred during the photoshoot.");
      setState(AppState.UPLOAD);
    }
  };

  const handleDeleteHistoryItem = async (id: string) => {
    try {
      const db = await openDB();
      const transaction = db.transaction(STORE_NAME, 'readwrite');
      transaction.objectStore(STORE_NAME).delete(id);
      setHistory(prev => prev.filter(item => item.id !== id));
    } catch (err) {
      console.error("Failed to delete item", err);
    }
  };

  const handleReset = () => {
    setReferenceImages([]);
    setGeneratedImages([]);
    setState(AppState.UPLOAD);
    setErrorMsg(null);
  };

  const handleToggleHistory = () => {
    setState(prev => prev === AppState.HISTORY ? AppState.UPLOAD : AppState.HISTORY);
  };

  const handleSelectHistoryItem = (item: HistoryItem) => {
    setReferenceImages(item.referenceImages);
    setGeneratedImages(item.results);
    setState(AppState.RESULTS);
  };

  return (
    <div className="min-h-screen bg-black text-zinc-100 font-sans selection:bg-white selection:text-black">
      <Header 
        onViewHistory={handleToggleHistory} 
        onGoHome={handleReset}
        hasHistory={history.length > 0}
      />

      <main className="max-w-7xl mx-auto px-4 py-12 md:py-20">
        {errorMsg && (
          <div className="mb-8 mx-auto max-w-2xl bg-red-950/30 border border-red-900/50 text-red-200 px-6 py-4 rounded-xl flex items-center gap-3 animate-in fade-in slide-in-from-top-2">
             <div className="w-2 h-2 rounded-full bg-red-500 shrink-0 shadow-[0_0_8px_rgba(239,68,68,0.5)]" />
             <p className="text-sm font-medium">{errorMsg}</p>
          </div>
        )}

        {state === AppState.CHECKING_KEY && (
          <div className="max-w-md mx-auto text-center space-y-8 mt-10">
            <div className="w-24 h-24 bg-zinc-900 rounded-3xl mx-auto flex items-center justify-center border border-zinc-800">
              <KeyRound className="w-10 h-10 text-zinc-400" />
            </div>
            <div className="space-y-2">
              <h2 className="text-3xl font-bold tracking-tight text-white uppercase italic">Access Required</h2>
              <p className="text-zinc-400">To use Lumière high-fidelity Gemini 3 Pro models, please select a billing-enabled API key.</p>
            </div>
            <div className="space-y-4">
              <Button onClick={handleSelectKey} fullWidth>Select API Key</Button>
              <p className="text-xs text-zinc-600">
                <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="underline hover:text-zinc-400">View billing documentation</a>
              </p>
            </div>
          </div>
        )}

        {state === AppState.HISTORY && (
          <HistoryView items={history} onSelectItem={handleSelectHistoryItem} onDeleteItem={handleDeleteHistoryItem} onBack={handleReset} />
        )}

        {state === AppState.UPLOAD && (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="text-center space-y-4">
              <h1 className="text-4xl md:text-5xl lg:text-7xl font-black tracking-tighter text-white uppercase italic">
                GY's LUMIÈRE <span className="text-transparent bg-clip-text bg-gradient-to-r from-zinc-200 to-zinc-600">STUDIO</span>
              </h1>
              <p className="text-lg text-zinc-500 max-w-2xl mx-auto font-light leading-relaxed">
                Transform single or multiple reference images into professional catalogs. <br className="hidden md:block" />
                Select your product category and provide multi-angle shots for precision results.
              </p>
            </div>
            <UploadZone onImagesReady={handleImagesSelected} />
          </div>
        )}

        {state === AppState.GENERATING && (
          <div className="max-w-2xl mx-auto text-center mt-12 space-y-10 animate-in zoom-in-95 duration-500">
            <div className="relative w-full aspect-[4/3] bg-zinc-900 rounded-3xl overflow-hidden border border-zinc-800 shadow-2xl">
              {referenceImages.length > 0 && (
                <img 
                  src={referenceImages[0]} 
                  alt="Reference" 
                  className="absolute inset-0 w-full h-full object-cover opacity-10 blur-3xl scale-125" 
                />
              )}
              <div className="absolute inset-0 flex flex-col items-center justify-center p-12">
                <Loader2 className="w-16 h-16 text-white animate-spin mb-8" />
                <h3 className="text-3xl font-bold text-white mb-2 uppercase tracking-tighter">In Production</h3>
                <p className="text-zinc-500 font-mono text-xs tracking-[0.4em] uppercase mb-10">{progress.currentTask}</p>
                <div className="w-full h-1 bg-zinc-800 rounded-full overflow-hidden mb-4">
                  <div className="h-full bg-white transition-all duration-1000 ease-in-out" style={{ width: `${(progress.completed / progress.total) * 100}%` }} />
                </div>
                <div className="flex justify-between w-full text-[10px] text-zinc-600 uppercase tracking-[0.5em] font-bold">
                   <span>Developing</span>
                   <span>{progress.completed} / {progress.total} Shots</span>
                </div>
              </div>
            </div>
          </div>
        )}

        {state === AppState.RESULTS && (
          <Gallery images={generatedImages} onReset={handleReset} />
        )}
      </main>
    </div>
  );
};

export default App;

