export type PartyBackgroundType = 'CLUB_LOUNGE' | 'ROOFTOP_PARTY' | 'PENTHOUSE_PARTY' | 'MINIMAL_PARTY';

export interface GeneratedImage {
  id: string;
  label: string;
  url: string;
  timestamp: number;
}

export interface PoseConfig {
