  promptDescription: string;
}

export interface HistoryItem {
  id: string;
  timestamp: number;
  referenceImages: string[];
  productType?: ProductType;
  poseStyle?: PoseStyle;
  backgroundStyle?: BackgroundStyle;
  partyBackground?: PartyBackgroundType;
  results: GeneratedImage[];
}

