  CHECKING_KEY = 'CHECKING_KEY',
  UPLOAD = 'UPLOAD',
  GENERATING = 'GENERATING',
  RESULTS = 'RESULTS',
  HISTORY = 'HISTORY',
  ERROR = 'ERROR'
}

