                accept="image/png, image/jpeg, image/jpg, image/webp"
                className="hidden"
              />

              <Button onClick={() => fileInputRef.current?.click()}>
                Select Images
              </Button>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="flex flex-wrap justify-center gap-4">
                {previews.map((src, idx) => (
                  <div key={idx} className="relative w-32 h-44 bg-zinc-900 rounded-lg overflow-hidden border border-zinc-700 shadow-lg">
                    <img src={src} alt="Preview" className="w-full h-full object-cover" />
                    <button 
                      onClick={() => removeImage(idx)}
                      className="absolute top-1 right-1 p-1 bg-black/50 hover:bg-black rounded-full text-white transition-colors"
                    >
                      <X className="w-3 h-3" />
                    </button>
                    <div className="absolute bottom-0 inset-x-0 bg-black/60 py-1 text-[9px] text-white uppercase font-bold">
                      Ref {idx + 1}
                    </div>
                  </div>
                ))}
                {previews.length < MAX_IMAGES && (
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-32 h-44 border-2 border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center gap-2 hover:border-zinc-600 hover:bg-zinc-900/50 transition-all text-zinc-500 hover:text-zinc-300"
                  >
                    <Plus className="w-6 h-6" />
                    <span className="text-xs font-medium">Add Angle</span>
                  </button>
                )}
              </div>

              <div className="flex flex-col items-center gap-4 pt-4">
                <Button onClick={handleStartGeneration} className="w-full max-w-md shadow-[0_0_20px_rgba(255,255,255,0.1)] h-12 text-lg">
                  Generate {selectedPoseIds.length} Shot{selectedPoseIds.length !== 1 ? 's' : ''}
                </Button>
                <button 
                  onClick={() => setPreviews([])}
                  className="text-xs text-zinc-500 hover:text-zinc-300 transition-colors uppercase tracking-widest font-bold"
                >
                  Clear All
                </button>
              </div>
            </div>
          )}

          <input 
            type="file" 
            ref={fileInputRef}
            onChange={handleChange}
            multiple
            accept="image/png, image/jpeg, image/jpg, image/webp"
            className="hidden"
          />

          {error && (
            <div className="mt-4 flex items-center gap-2 text-red-400 bg-red-950/30 px-4 py-2 rounded-lg border border-red-900/50 justify-center">
              <AlertCircle className="w-4 h-4" />
              <span className="text-sm">{error}</span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Header } from './components/Header';
import { UploadZone } from './components/UploadZone';
import { Gallery } from './components/Gallery';
import { HistoryView } from './components/HistoryView';
import { Button } from './components/Button';
import { AppState, GeneratedImage, GenerationProgress, HistoryItem, ProductType, PoseStyle, BackgroundStyle, PartyBackgroundType } from './types';
import { generatePhotoshoot } from './services/geminiService';
import { Loader2, KeyRound } from 'lucide-react';

// IndexedDB configuration for robust storage of high-res base64 images
const DB_NAME = 'LumiereStudioDB';
const STORE_NAME = 'history';
const DB_VERSION = 2; // Incremented version to handle referenceImages array

const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onupgradeneeded = (event) => {
      const db = request.result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
      // Migration logic if needed could go here
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(AppState.CHECKING_KEY);
  const [referenceImages, setReferenceImages] = useState<string[]>([]);
  const [generatedImages, setGeneratedImages] = useState<GeneratedImage[]>([]);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [progress, setProgress] = useState<GenerationProgress>({ total: 0, completed: 0, currentTask: '' });
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Initial Check for API Key & Load History
  useEffect(() => {
    const init = async () => {
      // 1. Check API Key Status
      const win = window as any;
      if (win.aistudio && await win.aistudio.hasSelectedApiKey()) {
        setState(AppState.UPLOAD);
      } else {
        setState(AppState.CHECKING_KEY);
      }

      // 2. Load History
      try {
        const db = await openDB();
        const transaction = db.transaction(STORE_NAME, 'readonly');
        const store = transaction.objectStore(STORE_NAME);
        const request = store.getAll();
        request.onsuccess = () => {
          const raw = request.result as any[];
          // Backward compatibility for single referenceImage history
          const migrated = raw.map(item => ({
            ...item,
            referenceImages: item.referenceImages || (item.referenceImage ? [item.referenceImage] : []),
            productType: item.productType || 'TOPS', // Default for old items
            poseStyle: item.poseStyle || 'COMMERCIAL',
            backgroundStyle: item.backgroundStyle || 'STUDIO_GREY',
            partyBackground: item.partyBackground || undefined
          })) as HistoryItem[];

          const sorted = migrated.sort((a, b) => b.timestamp - a.timestamp);
          setHistory(sorted);
        };
      } catch (err) {
        console.error("Failed to load history from IndexedDB", err);
      }
    };
    init();
  }, []);

  const handleSelectKey = async () => {
    setErrorMsg(null);
    const win = window as any;
    if (win.aistudio) {
      try {
        await win.aistudio.openSelectKey();
        setState(AppState.UPLOAD);
      } catch (e) {
        setErrorMsg("Failed to select API key. Please try again.");
      }
    } else {
      // Fallback for dev environments
      setState(AppState.UPLOAD);
    }
  };

  const handleImagesSelected = async (
    base64Array: string[], 
    productType: ProductType, 
    poseStyle: PoseStyle, 
    backgroundStyle: BackgroundStyle, 
    selectedPoseIds: string[],
    partyBackground?: PartyBackgroundType
  ) => {
    setReferenceImages(base64Array);
    setState(AppState.GENERATING);
    setErrorMsg(null);
    setGeneratedImages([]);

    try {
      const results = await generatePhotoshoot(
        base64Array, 
        productType, 
        poseStyle, 
        backgroundStyle, 
        selectedPoseIds, 
        (completed, total, task) => {
          setProgress({ completed, total, currentTask: task });
        },
        partyBackground
      );

      if (results.length === 0) {
        throw new Error("No images were successfully generated.");
      }

      const newItem: HistoryItem = {
        id: crypto.randomUUID?.() || Math.random().toString(36).substring(7),
        timestamp: Date.now(),
        referenceImages: base64Array,
        productType: productType,
        poseStyle: poseStyle,
        backgroundStyle: backgroundStyle,
        partyBackground: partyBackground,
        results: results
      };

      // Save to IndexedDB
      const db = await openDB();
      const transaction = db.transaction(STORE_NAME, 'readwrite');
      transaction.objectStore(STORE_NAME).add(newItem);

      setGeneratedImages(results);
      setHistory(prev => [newItem, ...prev]);
      setState(AppState.RESULTS);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "An unexpected error occurred during the photoshoot.");
      setState(AppState.UPLOAD);
    }
  };

  const handleDeleteHistoryItem = async (id: string) => {
    try {
      const db = await openDB();
      const transaction = db.transaction(STORE_NAME, 'readwrite');
      transaction.objectStore(STORE_NAME).delete(id);
      setHistory(prev => prev.filter(item => item.id !== id));
    } catch (err) {
      console.error("Failed to delete item", err);
    }
  };

  const handleReset = () => {
    setReferenceImages([]);
    setGeneratedImages([]);
    setState(AppState.UPLOAD);
    setErrorMsg(null);
  };

  const handleToggleHistory = () => {
    setState(prev => prev === AppState.HISTORY ? AppState.UPLOAD : AppState.HISTORY);
  };

  const handleSelectHistoryItem = (item: HistoryItem) => {
    setReferenceImages(item.referenceImages);
    setGeneratedImages(item.results);
    setState(AppState.RESULTS);
